/**
 * Launch-recovery pins for canonical recovery roots.
 *
 * A launch-recovery pin lets a fresh validator client start its replay AFTER a
 * one-off operator-bootstrap event without traversing receipts that were not
 * produced by the normal score-attested miner path. The pin asserts that, at a
 * specific (chainId, epochId, attainedAtBlock), the on-chain
 * `CoreTexRegistry.liveStateRoot(epoch)` equals `parentStateRoot` and ships the
 * matching packed substrate so replay can resume from that root forward.
 *
 * Operator-bootstrap receipts are kept on-chain as incident history. They are
 * not score-attested and are intentionally NOT replayed by clients that use the
 * launch-recovery pin. A client can opt out and replay from genesis with
 * `--full-history` or `CORETEX_REPLAY_FULL_HISTORY=1`, in which case the client
 * sees those receipts as ordinary advances and the eval-replay path WILL fail
 * for them (they have no `coretex-post-reveal-eval-report-v1` artifact). This
 * is by design — full-history clients audit the entire chain including the
 * operator incident, opting out of the recovery shortcut.
 *
 * The guard at sync time re-reads `liveStateRoot(epoch)` at `attainedAtBlock`
 * from the chain and fails closed if it does not match `parentStateRoot`, so
 * the pin cannot be silently substituted for a forked state.
 */
import type { CortexState } from '../state/types.js';
import { unpack } from '../state/codec.js';
import { bytesToHex, hexToBytes, merkleizeState } from '../state/merkle.js';

export interface LaunchRecoveryPin {
  readonly chainId: number;
  readonly epochId: number;
  /** The canonical post-recovery state root (== chain liveStateRoot(epoch) at attainedAtBlock). */
  readonly parentStateRoot: string;
  /** First block the validator should fetch logs from. Strictly greater than attainedAtBlock. */
  readonly fromBlock: number;
  /** Block at which the chain first reached parentStateRoot. The guard re-reads liveStateRoot at this block. */
  readonly attainedAtBlock: number;
  /** Tx that landed the final bootstrap advance (audit). */
  readonly attainedAtTx: string;
  /** transitionIndex of the final bootstrap advance. */
  readonly attainedAtTransitionIndex: number;
  readonly corpusRoot: string;
  readonly coreVersionHash: string;
  readonly activeFrontierRoot: string;
  /** Wallet address that signed/broadcast the operator-bootstrap receipts (audit only). */
  readonly bootstrapMiner: string;
  /** Production-scorer baseline recomputed against the post-recovery root (audit only). */
  readonly baselineParentScorePpm: number;
  /** Packed CortexState bytes; merkleizes to parentStateRoot. */
  readonly parentStatePackedHex: string;
  readonly note: string;
}

const BASE_MAINNET_EPOCH_115_PACKED_HEX = '';

const BASE_MAINNET_EPOCH_115: LaunchRecoveryPin = {
  chainId: 8453,
  epochId: 115,
  parentStateRoot: '0x4c7e19e2bfec553d0b3f07bc55e6c3f968dd569d95359f9569574c1ccfe773af',
  fromBlock: 47358409,
  attainedAtBlock: 47358408,
  attainedAtTx: '0x92d56e646d193905c668a8ff2cb83037f1f8713b7634dbd002de720d1bf7587e',
  attainedAtTransitionIndex: 5,
  corpusRoot: '0xb692b4a133963399257979bc5f632a0900d2d5d73dbadf191d3cf9889188e57e',
  coreVersionHash: '0x73172e2bc77e2f066a160bc94a48ae73c5221cf11591c3958c03aa5884793506',
  activeFrontierRoot: '0x5e1b6684c1ceed28de26035294e49c278de6a1d4d9f1bb26c4fcbab2d1187823',
  bootstrapMiner: '0x3021844b324333AA0530d8CDCBb3c9Dc1D09b67F',
  baselineParentScorePpm: 278923,
  parentStatePackedHex: BASE_MAINNET_EPOCH_115_PACKED_HEX,
  note:
    'Base mainnet epoch-115 launch recovery: 6 operator-bootstrap STATE_ADVANCE receipts '
    + '(transition indices 0..5) warmed the cold root with public MemoryIndex anchors. '
    + 'Operator bootstraps are not score-attested miner advances; clients replay forward '
    + 'from this canonical post-recovery root by default.',
};

function pinKey(chainId: number, epochId: number): string {
  return `${chainId}:${epochId}`;
}

const PINS = new Map<string, LaunchRecoveryPin>([
  [pinKey(BASE_MAINNET_EPOCH_115.chainId, BASE_MAINNET_EPOCH_115.epochId), BASE_MAINNET_EPOCH_115],
]);

/** Return the launch-recovery pin for a given chain + epoch, if one is shipped in this client release. */
export function resolveLaunchRecoveryPin(chainId: number, epochId: number): LaunchRecoveryPin | undefined {
  return PINS.get(pinKey(chainId, epochId));
}

/** All shipped pins (audit / introspection). */
export function listLaunchRecoveryPins(): readonly LaunchRecoveryPin[] {
  return [...PINS.values()];
}

/**
 * Decode the pin's packed substrate into a CortexState and verify its merkle
 * root equals the pin's parentStateRoot. Throws if the pin is corrupt.
 */
export function launchRecoveryParentState(pin: LaunchRecoveryPin): CortexState {
  const bytes = hexToBytes(pin.parentStatePackedHex);
  const state = unpack(bytes);
  const root = bytesToHex(merkleizeState(state)).toLowerCase();
  if (root !== pin.parentStateRoot.toLowerCase()) {
    throw new Error(
      `launch-recovery-pin chainId=${pin.chainId} epochId=${pin.epochId}: packed substrate merkles to ${root}, expected ${pin.parentStateRoot}`,
    );
  }
  return state;
}

/** Read the launch-recovery opt-out signal from CLI flags / env. */
export function launchRecoveryDisabledFromEnv(opts: {
  readonly fullHistoryFlag: boolean;
  readonly envFullHistory: string | undefined;
}): boolean {
  if (opts.fullHistoryFlag) return true;
  const v = (opts.envFullHistory ?? '').toLowerCase();
  return v === '1' || v === 'true' || v === 'yes';
}
